import json
import re

# Define replacement functions
def replace_all_cluj(text):
    # Replace Cluj variants preserving case
    text = re.sub(r'\bCluj-Napoca\b', 'Pantelimon', text, flags=re.IGNORECASE)
    text = re.sub(r'\bClujului\b', 'Pantelimonului', text, flags=re.IGNORECASE)
    text = re.sub(r'\bClujul\b', 'Pantelimonul', text, flags=re.IGNORECASE)
    text = re.sub(r'\bClujeni\b', 'Pantelimoneni', text, flags=re.IGNORECASE)
    text = re.sub(r'\bClujean\b', 'Pantelimonean', text, flags=re.IGNORECASE)
    text = re.sub(r'\bClujean\u0103\b', 'Pantelimoneanc\u0103', text, flags=re.IGNORECASE)
    text = re.sub(r'\bClujence\b', 'Pantelimonence', text, flags=re.IGNORECASE)
    text = re.sub(r'\bClujeanc\u0103\b', 'Pantelimoneanc\u0103', text, flags=re.IGNORECASE)
    text = re.sub(r'\bClujenilor\b', 'Pantelimoneni', text, flags=re.IGNORECASE)
    text = re.sub(r'\bClujeanului\b', 'Pantelimoneanului', text, flags=re.IGNORECASE)
    text = re.sub(r'\bCluj\b', 'Pantelimon', text, flags=re.IGNORECASE)
    return text

def replace_villages(text):
    replacements = {
        r'\bCiurila\b': 'Pantelimon',
        r'\bS\u0103licea\b': 'Pantelimon',
        r'\bBu\u0219teni\b': 'Pantelimon',
        r'\bBucegi\b': 'Pantelimon',
        r'\bTurda\b': 'Pantelimon',
        r'\bC\u00e2mpia Turzii\b': 'Pantelimon',
        r'\bTurda-Hotar\b': 'Pantelimon',
        r'\bPetrilaca\b': 'Pantelimon',
        r'\bPetrilac\u0103\b': 'Pantelimon',
        r'\bHotar\b': 'Pantelimon',
        r'\bPetrilaca Hotar\b': 'Pantelimon',
        r'\bHotar Petrilaca\b': 'Pantelimon',
        r'\bJucu\b': 'Pantelimon',
        r'\bFlore\u0219ti\b': 'Pantelimon',
        r'\bSome\u0219eni\b': 'Pantelimon',
        r'\bA\u0219chileu\b': 'Pantelimon',
        r'\bD\u0103b\u00e2ca\b': 'Pantelimon',
        r'\bDobrogei\b': 'Pantelimon',
        r'\bM\u0103r\u0103\u0219ti\b': 'Pantelimon',
        r'\bPata R\u00e2t\b': 'Pantelimon',
    }
    for pattern, repl in replacements.items():
        text = re.sub(pattern, repl, text, flags=re.IGNORECASE)
    return text

def replace_video_foto_audio(text):
    text = re.sub(r'^VIDEO\.\s*', 'VIDEO: ', text, flags=re.IGNORECASE)
    text = re.sub(r'^FOTO\.\s*', 'FOTO: ', text, flags=re.IGNORECASE)
    text = re.sub(r'^AUDIO\.\s*', 'AUDIO: ', text, flags=re.IGNORECASE)
    text = re.sub(r'^VIDEO:\s*', 'VIDEO: ', text, flags=re.IGNORECASE)
    text = re.sub(r'^FOTO:\s*', 'FOTO: ', text, flags=re.IGNORECASE)
    text = re.sub(r'^AUDIO:\s*', 'AUDIO: ', text, flags=re.IGNORECASE)
    text = re.sub(r'^FOTO/VIDEO\s*', 'FOTO/VIDEO: ', text, flags=re.IGNORECASE)
    return text

def process_text(text):
    text = replace_all_cluj(text)
    text = replace_villages(text)
    text = replace_video_foto_audio(text)
    return text

